// Auto-generated Thai+Latin font for jsPDF (Sarabun, subset: Thai + Latin + Latin-ext).
// Source: Google Fonts "Sarabun" via @fontsource/sarabun, Thai+Latin unicode ranges merged
// into a single TTF so jsPDF can render Thai text in generated PDFs.
//
// Usage:
//   import jsPDF from "jspdf";
//   import { registerThaiFont } from "./sarabunFont";
//
//   const doc = new jsPDF(...);
//   registerThaiFont(doc);
//   doc.setFont("Sarabun", "normal"); // or "bold"

const SARABUN_REGULAR_BASE64 =
  "";

const SARABUN_BOLD_BASE64 =
  "";

let registered = false;

export function registerThaiFont(doc: import("jspdf").jsPDF) {
  // VFS fonts are registered on the jsPDF module the first time this runs;
  // subsequent calls (e.g. for a new doc instance) just need addFont again.
  doc.addFileToVFS("Sarabun-Regular.ttf", SARABUN_REGULAR_BASE64);
  doc.addFont("Sarabun-Regular.ttf", "Sarabun", "normal");

  doc.addFileToVFS("Sarabun-Bold.ttf", SARABUN_BOLD_BASE64);
  doc.addFont("Sarabun-Bold.ttf", "Sarabun", "bold");

  registered = true;
}

export function isThaiFontRegistered() {
  return registered;
}